import torch
import torch.nn as nn
import torchvision.transforms as transforms
from torchvision import models
from flask import Flask, request, jsonify
from PIL import Image
import io
import hashlib
import numpy as np
from scipy import stats
import json

app = Flask(__name__)

device = torch.device("cuda" if torch.cuda.is_available() else "cpu")

model = models.resnet50(pretrained=True)
model = model.to(device)
model.eval()

with open('imagenet_classes.json', 'r') as f:
    class_names = json.load(f)

transform = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
])


def detect_adversarial_perturbations(image_tensor):
    noise_level = torch.std(image_tensor).item()
    if noise_level > 0.5:
        return True
    
    freq_domain = torch.fft.fft2(image_tensor)
    high_freq_energy = torch.abs(freq_domain[:, :, -50:, -50:]).mean().item()
    if high_freq_energy > 10.0:
        return True
    
    return False


def ensemble_prediction(image_tensor, num_augmentations=5):
    predictions = []
    
    with torch.no_grad():
        output = model(image_tensor.unsqueeze(0).to(device))
        predictions.append(torch.softmax(output, dim=1).cpu().numpy())
    
    for _ in range(num_augmentations):
        noise = torch.randn_like(image_tensor) * 0.01
        augmented = image_tensor + noise
        augmented = torch.clamp(augmented, 0, 1)
        
        with torch.no_grad():
            output = model(augmented.unsqueeze(0).to(device))
            predictions.append(torch.softmax(output, dim=1).cpu().numpy())
    
    predictions = np.array(predictions)
    mean_pred = np.mean(predictions, axis=0)
    std_pred = np.std(predictions, axis=0)
    
    max_std = np.max(std_pred)
    if max_std > 0.15:
        return None, None, True
    
    return mean_pred, std_pred, False


def gradient_based_detection(image_tensor):
    image_tensor.requires_grad = True
    
    output = model(image_tensor.unsqueeze(0).to(device))
    loss = torch.max(output)
    loss.backward()
    
    gradient_magnitude = torch.abs(image_tensor.grad).mean().item()
    
    image_tensor.requires_grad = False
    
    if gradient_magnitude > 0.5:
        return True
    
    return False


def input_transformation_defense(image_tensor):
    transformations = []
    
    jpeg_quality = 75
    img_pil = transforms.ToPILImage()(image_tensor)
    buffer = io.BytesIO()
    img_pil.save(buffer, format='JPEG', quality=jpeg_quality)
    buffer.seek(0)
    img_pil = Image.open(buffer)
    transformed = transform(img_pil)
    transformations.append(transformed)
    
    bit_depth = 7
    quantized = torch.round(image_tensor * (2 ** bit_depth)) / (2 ** bit_depth)
    transformations.append(quantized)
    
    median_filtered = torch.from_numpy(
        np.array([stats.mode(image_tensor[c].numpy().flatten(), keepdims=False)[0] 
                  for c in range(3)])
    ).float().view(3, 1, 1).expand_as(image_tensor)
    transformations.append(median_filtered)
    
    return transformations


def confidence_calibration(confidence, prediction_variance):
    calibrated_confidence = confidence * (1 - prediction_variance * 2)
    calibrated_confidence = max(0.0, min(1.0, calibrated_confidence))
    return calibrated_confidence


@app.route('/classify', methods=['POST'])
def classify_image():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    file = request.files['image']
    
    try:
        image = Image.open(io.BytesIO(file.read())).convert('RGB')
        image_tensor = transform(image)
        
        if detect_adversarial_perturbations(image_tensor):
            return jsonify({
                'error': 'Potential adversarial input detected',
                'predicted_class': 'REJECTED',
                'confidence': 0.0,
                'adversarial_detected': True
            }), 400
        
        if gradient_based_detection(image_tensor.to(device)):
            return jsonify({
                'error': 'Gradient-based adversarial attack detected',
                'predicted_class': 'REJECTED',
                'confidence': 0.0,
                'adversarial_detected': True
            }), 400
        
        mean_pred, std_pred, is_adversarial = ensemble_prediction(image_tensor)
        
        if is_adversarial:
            return jsonify({
                'error': 'High prediction variance detected - possible adversarial input',
                'predicted_class': 'REJECTED',
                'confidence': 0.0,
                'adversarial_detected': True
            }), 400
        
        transformed_inputs = input_transformation_defense(image_tensor)
        
        all_predictions = [mean_pred]
        for transformed in transformed_inputs:
            with torch.no_grad():
                output = model(transformed.unsqueeze(0).to(device))
                pred = torch.softmax(output, dim=1).cpu().numpy()
                all_predictions.append(pred)
        
        all_predictions = np.array(all_predictions)
        final_prediction = np.mean(all_predictions, axis=0)[0]
        prediction_variance = np.std(all_predictions, axis=0)[0]
        
        predicted_class_idx = np.argmax(final_prediction)
        confidence = float(final_prediction[predicted_class_idx])
        variance = float(prediction_variance[predicted_class_idx])
        
        calibrated_confidence = confidence_calibration(confidence, variance)
        
        if variance > 0.1:
            return jsonify({
                'warning': 'High variance across transformations',
                'predicted_class': class_names[predicted_class_idx],
                'confidence': calibrated_confidence,
                'raw_confidence': confidence,
                'variance': variance,
                'adversarial_detected': True
            }), 200
        
        return jsonify({
            'predicted_class': class_names[predicted_class_idx],
            'confidence': calibrated_confidence,
            'raw_confidence': confidence,
            'variance': variance,
            'adversarial_detected': False
        }), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)